// eBay Skin token values — from benchmark
// ---------------------------------------------------------------------------
const EBAY_DURATIONS = [
  { name: 'motion.duration.instant', value: 17, tier: 'instant', note: '1 frame at 60fps (16.67ms rounded)' },
  { name: 'motion.duration.short.1', value: 50,  tier: 'short' },
  { name: 'motion.duration.short.2', value: 83,  tier: 'short' },
  { name: 'motion.duration.short.3', value: 167, tier: 'short' },
  { name: 'motion.duration.medium.1', value: 250, tier: 'medium' },
  { name: 'motion.duration.medium.2', value: 333, tier: 'medium' },
  { name: 'motion.duration.medium.3', value: 500, tier: 'medium', note: 'Default component pairing with standard easing' },
  { name: 'motion.duration.long.1',  value: 667, tier: 'long' },
  { name: 'motion.duration.long.2',  value: 883, tier: 'long' },
  { name: 'motion.duration.long.3',  value: 1000, tier: 'long' },
];

const EBAY_EASINGS = [
  {
    name: 'motion.easing.standard',
    curve: [0.3, 0, 0, 1],
    direction: 'bidirectional',
    character: 'standard',
    desc: 'Primary curve. "Responsive and elegant." Strong deceleration.',
  },
  {
    name: 'motion.easing.quick.enter',
    curve: [0, 0, 0, 1],
    direction: 'enter',
    character: 'quick',
    desc: 'Near-instant start, full deceleration.',
  },
  {
    name: 'motion.easing.quick.exit',
    curve: [1, 0, 0, 1],
    direction: 'exit',
    character: 'quick',
    desc: 'Near-instant acceleration, then stop.',
  },
  {
    name: 'motion.easing.soft.enter',
    curve: [0, 0, 0.7, 1],
    direction: 'enter',
    character: 'soft',
    desc: 'Gentler deceleration on arrival.',
  },
  {
    name: 'motion.easing.soft.exit',
    curve: [0.3, 0, 1, 1],
    direction: 'exit',
    character: 'soft',
    desc: 'Gradual acceleration on departure.',
  },
  {
    name: 'motion.easing.continuous',
    curve: [0.3, 0, 0.7, 1],
    direction: 'looping',
    character: 'continuous',
    desc: 'Symmetric — for sustained/looping animations.',
  },
  {
    name: 'motion.easing.bounce',
    curve: [0.3, 0, 0, 1.5],
    direction: 'expressive',
    character: 'bounce',
    desc: 'Y2 = 1.5 — CSS cubic-bezier overshoot approximation. Not a spring.',
  },
  {
    name: 'motion.easing.linear',
    curve: [0, 0, 1, 1],
    direction: 'utility',
    character: 'linear',
    desc: 'Progress bars, loaders.',
  },
];

function cb([x1, y1, x2, y2]) {
  return `cubic-bezier(${x1}, ${y1}, ${x2}, ${y2})`;
}

function easingSVG([x1, y1, x2, y2], color = '#e53238') {
  // Clamp y to visible range for bounce curves
  const pts = [];
  for (let i = 0; i <= 20; i++) {
    const t = i / 20;
    const bx = 3*(1-t)*(1-t)*t*x1 + 3*(1-t)*t*t*x2 + t*t*t;
    const rawBy = 3*(1-t)*(1-t)*t*y1 + 3*(1-t)*t*t*y2 + t*t*t;
    const by = Math.max(-0.3, Math.min(1.3, rawBy));
    pts.push([bx * 40, (1 - by) * 8]);
  }
  const d = pts.map(([x, y], i) => `${i === 0 ? 'M' : 'L'}${x.toFixed(1)} ${y.toFixed(1)}`).join(' ');
  return `<svg width="40" height="10" viewBox="0 0 40 10" style="overflow:visible;display:inline-block;vertical-align:middle">
    <path d="${d}" fill="none" stroke="${color}" stroke-width="1.5"/>
  </svg>`;
}

